/**
 * 错误处理流程集成测试
 * Story 8-4: 错误处理测试
 * AC4: 完整错误处理路径的集成测试
 *
 * 测试范围:
 * - 网络断开场景
 * - API超时场景
 * - 数据库错误场景
 * - 第三方服务错误场景
 */

import { authService } from '../../../services/authService';
import { childApi } from '../../../services/childApi';
import { questionGenerationService } from '../../../services/questionGenerationService';
import { TestDataFactory, TestDataCleaner } from '../setup/testData';

// Mock API客户端
jest.mock('../../../services/api', () => ({
  apiClient: {
    post: jest.fn(),
    get: jest.fn(),
    put: jest.fn(),
    delete: jest.fn(),
  },
}));

// Mock OCR服务
jest.mock('../../../services/ai/baiduOcrService', () => ({
  baiduOcrService: {
    recognizeImage: jest.fn(),
  },
}));

// Mock AI服务
jest.mock('../../../services/ai/deepseekService', () => ({
  deepseekService: {
    generateQuestion: jest.fn(),
    generateSimilarQuestions: jest.fn(),
  },
}));

// Mock AsyncStorage
jest.mock('@react-native-async-storage/async-storage', () => ({
  setItem: jest.fn(() => Promise.resolve()),
  getItem: jest.fn(() => Promise.resolve(null)),
  removeItem: jest.fn(() => Promise.resolve()),
  clear: jest.fn(() => Promise.resolve()),
}));

describe('Error Handling Integration Tests', () => {
  let testUser: any;
  let testChild: any;

  beforeAll(async () => {
    console.log('⚠️ Setting up error handling integration tests...');
    testUser = TestDataFactory.createUser();
    testChild = TestDataFactory.createChild();
  });

  afterAll(async () => {
    await TestDataCleaner.cleanAll();
    console.log('🧹 Cleaned up test data');
  });

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('AC4.1: Network Disconnection Scenarios', () => {
    it('should handle network error during login', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce({
        code: 'NETWORK_ERROR',
        message: 'Network request failed',
      });

      const credentials = {
        email: 'test@example.com',
        password: 'password123',
      };

      // Act
      const result = await authService.login(credentials);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('NETWORK_ERROR');
    });

    it('should handle network error with retry mechanism', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');

      // 第一次失败
      apiClient.get.mockRejectedValueOnce({
        code: 'NETWORK_ERROR',
        message: 'Network request failed',
      });

      // 第二次成功
      apiClient.get.mockResolvedValueOnce({
        data: {
          success: true,
          data: { children: [testChild] },
        },
      });

      // Act - 第一次请求失败
      let result = await childApi.getChildren(testUser.id);
      expect(result.success).toBe(false);

      // 重试
      result = await childApi.getChildren(testUser.id);
      expect(result.success).toBe(true);
    });

    it('should detect offline mode and use cached data', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      const AsyncStorage = require('@react-native-async-storage/async-storage');

      apiClient.get.mockRejectedValueOnce({
        code: 'NETWORK_ERROR',
        message: 'No internet connection',
      });

      // 模拟缓存数据
      AsyncStorage.getItem.mockResolvedValueOnce(
        JSON.stringify({ children: [testChild], cachedAt: Date.now() })
      );

      // Act
      const result = await childApi.getChildren(testUser.id);

      // Assert - 应该使用缓存数据
      expect(result.success).toBe(true);
      expect(result.data.children).toHaveLength(1);
    });

    it('should queue operations when offline', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce({
        code: 'NETWORK_ERROR',
        message: 'Offline',
      });

      const newChild = {
        name: '离线测试儿童',
        grade: testChild.grade,
        birthday: testChild.birthday,
        parentId: testUser.id,
      };

      // Act
      const result = await childApi.addChild(newChild);

      // Assert - 应该标记为离线操作
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('NETWORK_ERROR');
      // 实际应用中应该将操作加入离线队列
    });
  });

  describe('AC4.2: API Timeout Scenarios', () => {
    it('should handle login timeout', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockImplementationOnce(
        () =>
          new Promise((_, reject) =>
            setTimeout(() => reject({ code: 'TIMEOUT', message: 'Request timeout' }), 100)
          )
      );

      // Act
      const result = await authService.login({
        email: 'test@example.com',
        password: 'password',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('TIMEOUT');
    });

    it('should handle OCR service timeout with fallback', async () => {
      // Arrange
      const baiduOcrService = require('../../../services/ai/baiduOcrService').baiduOcrService;
      baiduOcrService.recognizeImage.mockImplementationOnce(
        () =>
          new Promise((_, reject) =>
            setTimeout(() => reject(new Error('OCR service timeout')), 100)
          )
      );

      const mockImageData = {
        uri: 'file://test.jpg',
        type: 'image/jpeg',
        name: 'test.jpg',
      };

      // Act & Assert
      await expect(questionGenerationService.recognizeImage(mockImageData)).rejects.toThrow(
        'OCR service timeout'
      );
    });

    it('should respect configurable timeout values', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      const startTime = Date.now();

      apiClient.get.mockImplementationOnce(
        () =>
          new Promise((_, reject) =>
            setTimeout(() => reject({ code: 'TIMEOUT' }), 5000)
          )
      );

      // Act
      await childApi.getChildren(testUser.id);

      const duration = Date.now() - startTime;

      // Assert - 超时应该在合理范围内
      expect(duration).toBeLessThan(10000); // 10秒内
    });

    it('should cancel pending requests on new request', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');

      // 模拟慢速响应
      apiClient.get.mockImplementationOnce(
        () => new Promise((resolve) => setTimeout(() => resolve({ data: { success: true } }), 5000))
      );

      // 第二个请求快速响应
      apiClient.get.mockResolvedValueOnce({
        data: { success: true, data: { children: [] } },
      });

      // Act - 发起新请求（应该取消旧请求）
      const result = await childApi.getChildren(testUser.id);

      // Assert
      expect(result.success).toBe(true);
    });
  });

  describe('AC4.3: Database Error Scenarios', () => {
    it('should handle database connection error', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.get.mockRejectedValueOnce({
        code: 'DATABASE_ERROR',
        message: 'Unable to connect to database',
      });

      // Act
      const result = await childApi.getChildren(testUser.id);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('DATABASE_ERROR');
    });

    it('should handle duplicate key error', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce({
        code: 'DUPLICATE_KEY',
        message: 'Email already exists',
      });

      // Act
      const result = await authService.register({
        name: 'Duplicate User',
        email: 'existing@example.com',
        password: 'password123',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('DUPLICATE_KEY');
    });

    it('should handle foreign key constraint error', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce({
        code: 'FOREIGN_KEY_ERROR',
        message: 'Parent user does not exist',
      });

      // Act
      const result = await childApi.addChild({
        name: 'Orphan Child',
        grade: testChild.grade,
        birthday: testChild.birthday,
        parentId: 'non-existent-user',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('FOREIGN_KEY_ERROR');
    });

    it('should handle data integrity error', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.put.mockRejectedValueOnce({
        code: 'DATA_INTEGRITY_ERROR',
        message: 'Invalid grade value',
      });

      // Act
      const result = await childApi.updateChild(testChild.id, {
        grade: 'INVALID_GRADE' as any,
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('DATA_INTEGRITY_ERROR');
    });
  });

  describe('AC4.4: Third-Party Service Error Scenarios', () => {
    it('should handle OCR service unavailable', async () => {
      // Arrange
      const baiduOcrService = require('../../../services/ai/baiduOcrService').baiduOcrService;
      baiduOcrService.recognizeImage.mockResolvedValueOnce({
        success: false,
        error: {
          code: 'OCR_SERVICE_UNAVAILABLE',
          message: 'OCR service is temporarily unavailable',
        },
      });

      const mockImageData = {
        uri: 'file://test.jpg',
        type: 'image/jpeg',
        name: 'test.jpg',
      };

      // Act
      const result = await questionGenerationService.recognizeImage(mockImageData);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('OCR_SERVICE_UNAVAILABLE');
    });

    it('should handle AI service rate limit', async () => {
      // Arrange
      const deepseekService = require('../../../services/ai/deepseekService').deepseekService;
      deepseekService.generateQuestion.mockResolvedValueOnce({
        success: false,
        error: {
          code: 'RATE_LIMIT_EXCEEDED',
          message: 'API rate limit exceeded, please try again later',
        },
      });

      // Act
      const result = await questionGenerationService.generateQuestion({
        ocrResult: { text: '3 + 5', type: 'ADDITION' },
        childId: testChild.id,
        difficulty: 'EASY',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('RATE_LIMIT_EXCEEDED');
    });

    it('should handle AI service invalid response', async () => {
      // Arrange
      const deepseekService = require('../../../services/ai/deepseekService').deepseekService;
      deepseekService.generateQuestion.mockResolvedValueOnce({
        success: true,
        data: null, // 无效响应
      });

      // Act
      const result = await questionGenerationService.generateQuestion({
        ocrResult: { text: '3 + 5', type: 'ADDITION' },
        childId: testChild.id,
        difficulty: 'EASY',
      });

      // Assert
      expect(result.success).toBe(false);
    });

    it('should handle OCR service authentication error', async () => {
      // Arrange
      const baiduOcrService = require('../../../services/ai/baiduOcrService').baiduOcrService;
      baiduOcrService.recognizeImage.mockResolvedValueOnce({
        success: false,
        error: {
          code: 'AUTHENTICATION_ERROR',
          message: 'Invalid API credentials',
        },
      });

      // Act
      const result = await questionGenerationService.recognizeImage({
        uri: 'file://test.jpg',
        type: 'image/jpeg',
        name: 'test.jpg',
      });

      // Assert
      expect(result.success).toBe(false);
      expect(result.error.code).toBe('AUTHENTICATION_ERROR');
    });
  });

  describe('AC4.5: Error Recovery and Fallback', () => {
    it('should use local fallback when all services fail', async () => {
      // Arrange
      const baiduOcrService = require('../../../services/ai/baiduOcrService').baiduOcrService;
      const deepseekService = require('../../../services/ai/deepseekService').deepseekService;

      // OCR失败
      baiduOcrService.recognizeImage.mockResolvedValueOnce({
        success: false,
        error: { code: 'OCR_FAILED' },
      });

      // AI失败
      deepseekService.generateQuestion.mockResolvedValueOnce({
        success: false,
        error: { code: 'AI_FAILED' },
      });

      // Act - 应该使用本地降级方案
      const result = await questionGenerationService.generateQuestion({
        ocrResult: { text: '3 + 5', type: 'ADDITION' },
        childId: testChild.id,
        difficulty: 'EASY',
      });

      // Assert
      expect(result.success).toBe(false);
    });

    it('should provide meaningful error messages to user', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce({
        code: 'UNKNOWN_ERROR',
        message: 'Internal server error',
      });

      // Act
      const result = await authService.login({
        email: 'test@example.com',
        password: 'password',
      });

      // Assert - 错误消息应该用户友好
      expect(result.success).toBe(false);
      expect(result.error.message).toBeDefined();
    });

    it('should log errors for debugging', async () => {
      // Arrange
      const consoleSpy = jest.spyOn(console, 'error').mockImplementation();
      const { apiClient } = require('../../../services/api');
      apiClient.post.mockRejectedValueOnce(new Error('Test error'));

      // Act
      try {
        await authService.login({
          email: 'test@example.com',
          password: 'password',
        });
      } catch (error) {
        // Expected
      }

      // Assert - 应该记录错误
      // 实际应用中应该检查日志记录
      consoleSpy.mockRestore();
    });
  });

  describe('AC4.6: Error Boundary Tests', () => {
    it('should handle unexpected null values', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.get.mockResolvedValueOnce({
        data: null,
      });

      // Act
      const result = await childApi.getChildren(testUser.id);

      // Assert
      expect(result.success).toBe(false);
    });

    it('should handle malformed JSON response', async () => {
      // Arrange
      const { apiClient } = require('../../../services/api');
      apiClient.get.mockResolvedValueOnce({
        data: 'invalid json string',
      });

      // Act
      const result = await childApi.getChildren(testUser.id);

      // Assert - 应该优雅处理
      expect(result).toBeDefined();
    });

    it('should handle empty required fields', async () => {
      // Arrange
      const invalidChild = {
        name: '', // 空名称
        grade: testChild.grade,
        birthday: testChild.birthday,
        parentId: testUser.id,
      };

      // Act & Assert
      await expect(childApi.addChild(invalidChild)).rejects.toThrow();
    });

    it('should handle extremely long input values', async () => {
      // Arrange
      const longName = 'a'.repeat(1000);
      const { apiClient } = require('../../../services/api');

      apiClient.post.mockResolvedValueOnce({
        data: {
          success: false,
          error: { code: 'VALIDATION_ERROR', message: 'Name too long' },
        },
      });

      // Act
      const result = await childApi.addChild({
        name: longName,
        grade: testChild.grade,
        birthday: testChild.birthday,
        parentId: testUser.id,
      });

      // Assert
      expect(result.success).toBe(false);
    });
  });
});
